"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { useCart } from "@/lib/CartContext";
import { useAuth } from "@/lib/AuthProvider";
import { ArrowLeft, CreditCard, MapPin, CheckCircle, ShoppingBag, Home } from "lucide-react";

// Lista de Províncias de Angola
const PROVINCIAS_ANGOLA = [
  "Luanda", "Bengo", "Benguela", "Bié", "Cabinda", "Cunene", "Huambo", 
  "Huíla", "Kuando Kubango", "Kwanza Norte", "Kwanza Sul", "Lunda Norte", 
  "Lunda Sul", "Malanje", "Moxico", "Namibe", "Uíge", "Zaire"
];

export default function CheckoutPage() {
  const { cart, clearCart } = useCart(); // Adicionado clearCart
  const { user } = useAuth();
  const router = useRouter();
  
  const [metodoPagamento, setMetodoPagamento] = useState("referencia");
  const [isFinished, setIsFinished] = useState(false);
  const [orderID, setOrderID] = useState("");

  // Estados do Formulário
  const [formData, setFormData] = useState({
    provincia: "Luanda",
    municipio: "",
    telefone: ""
  });

  useEffect(() => {
    if (!user) {
      const currentPath = window.location.pathname;
      router.push(`/auth/login?returnTo=${currentPath}`);
    }
  }, [user, router]);

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-white">
        <p className="text-gray-400 animate-pulse font-bold tracking-widest uppercase text-xs">
          Verificando Autenticação...
        </p>
      </div>
    );
  }

  const totalGeral = cart.reduce((acc, item) => acc + item.price * item.quantity, 0);

  const handleFinalizarPedido = (e: React.FormEvent) => {
    e.preventDefault();
    
    // Gerar um ID de pedido único
    const newOrderID = `BEL-${Math.floor(Math.random() * 90000) + 10000}`;
    
    // CRIAR OBJETO DO PEDIDO PARA O ADMIN
    const novoPedido = {
      id: newOrderID,
      cliente: user.name,
      email: user.email,
      telefone: formData.telefone,
      localidade: `${formData.provincia}, ${formData.municipio}`,
      itens: cart,
      total: totalGeral,
      status: "Pendente",
      data: new Date().toLocaleDateString('pt-PT'),
      metodo: metodoPagamento
    };

    // Salvar no localStorage para o Admin ver
    const pedidosExistentes = JSON.parse(localStorage.getItem("nani_orders") || "[]");
    localStorage.setItem("nani_orders", JSON.stringify([novoPedido, ...pedidosExistentes]));

    setOrderID(newOrderID);
    setIsFinished(true);
    clearCart(); // Limpa o carrinho após a compra
  };

  if (isFinished) {
    return (
      <div className="min-h-screen bg-white flex flex-col items-center justify-center p-6 text-center">
        <div className="w-24 h-24 bg-green-100 rounded-full flex items-center justify-center mb-6 animate-bounce">
          <CheckCircle size={60} className="text-green-600" />
        </div>
        <h1 className="text-3xl font-bold text-gray-800 mb-2">Compra Concluída!</h1>
        <p className="text-gray-500 max-w-md mb-8">
          Obrigada pela preferência, <span className="font-bold text-[#9D6E42]">{user.name}</span>! <br/>
          O seu pedido <span className="font-black text-gray-800">#{orderID}</span> foi recebido com sucesso.
        </p>

        <div className="flex flex-col sm:flex-row gap-4 w-full max-w-md">
          <Link href="/products" className="flex-1 bg-[#9C7C50] text-white py-4 rounded-xl font-bold flex items-center justify-center gap-2">
            <ShoppingBag size={20} /> Continuar
          </Link>
          <Link href="/" className="flex-1 border border-gray-200 text-gray-600 py-4 rounded-xl font-bold flex items-center justify-center gap-2">
            <Home size={20} /> Início
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#F7F7F7] font-sans text-gray-700 pb-12">
      <header className="bg-white shadow-sm p-4 sticky top-0 z-50">
        <div className="max-w-5xl mx-auto flex items-center justify-between">
          <Link href="/products/carrinho" className="flex items-center gap-2 text-[#9C7C50] font-bold text-sm">
            <ArrowLeft size={18} /> Revisar Carrinho
          </Link>
          <h1 className="text-lg font-black uppercase tracking-widest text-gray-800">Checkout</h1>
          <div className="w-20"></div>
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <form onSubmit={handleFinalizarPedido} className="space-y-6">
            
            {/* ENDEREÇO COM SELECTS */}
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
              <div className="flex items-center gap-2 mb-6 text-[#9C7C50]">
                <MapPin size={20} />
                <h2 className="font-bold text-gray-800">Dados de Entrega</h2>
              </div>
              <div className="space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase ml-1">Província</label>
                    <select 
                      required
                      className="w-full p-3 bg-gray-50 border border-gray-100 rounded-xl outline-none focus:ring-2 focus:ring-[#9C7C50]/20"
                      value={formData.provincia}
                      onChange={(e) => setFormData({...formData, provincia: e.target.value})}
                    >
                      {PROVINCIAS_ANGOLA.map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase ml-1">Município / Bairro</label>
                    <input 
                      required
                      type="text" 
                      placeholder="Ex: Talatona / Lar do Patriota" 
                      className="w-full p-3 bg-gray-50 border border-gray-100 rounded-xl outline-none focus:ring-2 focus:ring-[#9C7C50]/20"
                      value={formData.municipio}
                      onChange={(e) => setFormData({...formData, municipio: e.target.value})}
                    />
                  </div>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase ml-1">Telefone de Contacto (WhatsApp)</label>
                  <input 
                    required
                    type="tel" 
                    placeholder="9xx xxx xxx" 
                    className="w-full p-3 bg-gray-50 border border-gray-100 rounded-xl outline-none focus:ring-2 focus:ring-[#9C7C50]/20"
                    value={formData.telefone}
                    onChange={(e) => setFormData({...formData, telefone: e.target.value})}
                  />
                </div>
              </div>
            </div>

            {/* MÉTODO PAGAMENTO */}
            <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100">
              <div className="flex items-center gap-2 mb-6 text-[#9C7C50]">
                <CreditCard size={20} />
                <h2 className="font-bold text-gray-800">Pagamento</h2>
              </div>
              <div className="space-y-3">
                <label className={`flex items-center justify-between p-4 border rounded-2xl cursor-pointer transition-all ${metodoPagamento === 'referencia' ? 'border-[#9C7C50] bg-[#9C7C50]/5' : 'border-gray-100'}`}>
                  <div className="flex items-center gap-3">
                    <input type="radio" checked={metodoPagamento === 'referencia'} onChange={() => setMetodoPagamento('referencia')} className="accent-[#9C7C50]" />
                    <span className="text-sm font-bold">Referência Multicaixa (Pagamento Prévio)</span>
                  </div>
                </label>
                <label className={`flex items-center justify-between p-4 border rounded-2xl cursor-pointer transition-all ${metodoPagamento === 'entrega' ? 'border-[#9C7C50] bg-[#9C7C50]/5' : 'border-gray-100'}`}>
                  <div className="flex items-center gap-3">
                    <input type="radio" checked={metodoPagamento === 'entrega'} onChange={() => setMetodoPagamento('entrega')} className="accent-[#9C7C50]" />
                    <span className="text-sm font-bold">Pagar no Acto da Entrega (TPA/Cash)</span>
                  </div>
                </label>
              </div>
            </div>

            <button type="submit" className="w-full bg-[#9C7C50] text-white py-5 rounded-3xl font-black uppercase tracking-widest hover:scale-[1.02] active:scale-95 transition-all shadow-xl shadow-[#9C7C50]/20">
              Finalizar Pedido • AOA {totalGeral.toLocaleString()}
            </button>
          </form>

          {/* RESUMO */}
          <div className="bg-white p-8 rounded-[40px] shadow-sm border border-gray-100 h-fit sticky top-24">
            <h2 className="font-black uppercase text-[10px] tracking-widest text-gray-400 mb-6">Teu Carrinho</h2>
            <div className="space-y-4 mb-8">
              {cart.map((item) => (
                <div key={item.id} className="flex items-center gap-4">
                  <img src={item.image} className="w-16 h-16 object-cover rounded-2xl" alt="" />
                  <div className="flex-1">
                    <p className="font-bold text-gray-800 text-sm">{item.name}</p>
                    <p className="text-xs font-bold text-[#9C7C50]">{item.quantity}x AOA {item.price.toLocaleString()}</p>
                  </div>
                </div>
              ))}
            </div>
            <div className="border-t pt-6">
              <div className="flex justify-between items-center text-2xl font-black text-gray-900">
                <span className="text-sm uppercase tracking-widest text-gray-400">Total</span>
                <span>AOA {totalGeral.toLocaleString()}</span>
              </div>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}